"""Builds process-gaps.json — fills the remaining 'to build' Process tasks of the
2026 ECO (41% domain): value delivery, resources, procurement, finances,
quality+sustainability, status communication, closure.
Situational/judgement, bilingual FR/EN.
Tagging:
  - pr3 value delivery  -> knowledge_area=pr_value (new area), pmbok_ref=PR.3
  - pr4 resources       -> knowledge_area=resource,    refs 9.x   (existing KA, zero wiring)
  - pr5 procurement     -> knowledge_area=procurement, refs 12.x  (existing KA, zero wiring)
  - pr6 finances        -> knowledge_area=cost,        refs 7.x   (existing KA, zero wiring)
  - pr7 quality+ESG     -> knowledge_area=quality,     refs 8.x   (existing KA, zero wiring)
  - pr9 status comms    -> knowledge_area=comms,       pmbok_ref=PR.9
  - pr10 closure        -> knowledge_area=integration, refs 4.7   (deepens the amorce)
These finally light up the shallow KAs: cost, quality, resource, procurement.
"""
import json, os

def it(area, ref, n, grp, comp, diff, fr_p, en_p, fr_o, en_o, ans, fr_r, en_r):
    return {"id": f"pr-x-{ref}-{n:02d}", "type": "scenario" if diff >= 2 else "mcq",
            "knowledge_area": area, "process_group": grp, "pmbok_ref": ref,
            "competency": comp, "difficulty": diff,
            "prompt": {"fr": fr_p, "en": en_p}, "options": {"fr": fr_o, "en": en_o},
            "answer_index": ans, "rationale": {"fr": fr_r, "en": en_r}}

